	raw := state.GetInstances()

	var records []session.InstanceData
	if err := json.Unmarshal(raw, &records); err != nil {
		return fmt.Sprintf("error: %v\n", err)
	}

	// Apply optional status filter.
	if len(statusFilters) > 0 {
		filterSet := make(map[string]struct{}, len(statusFilters))
		for _, f := range statusFilters {
			filterSet[strings.ToLower(f)] = struct{}{}
		}
		filtered := records[:0]
		for _, r := range records {
			if _, ok := filterSet[statusString(r.Status)]; ok {
				filtered = append(filtered, r)
			}
		}
		records = filtered
	}

	if len(records) == 0 {
		if format == "json" {
			return "[]\n"
		}
		return "no instances\n"
	}

	switch format {
	case "json":
		type jsonRecord struct {
			Title     string `json:"title"`
			Status    string `json:"status"`
			Branch    string `json:"branch"`
			Program   string `json:"program"`
			TaskFile  string `json:"task_file,omitempty"`
			AgentType string `json:"agent_type,omitempty"`
			CreatedAt string `json:"created_at,omitempty"`
		}
		out := make([]jsonRecord, 0, len(records))
		for _, r := range records {
			var createdAt string
			if !r.CreatedAt.IsZero() {
				createdAt = r.CreatedAt.Format("2006-01-02T15:04:05Z07:00")
			}
			out = append(out, jsonRecord{
				Title:     r.Title,
				Status:    statusString(r.Status),
				Branch:    r.Branch,
				Program:   r.Program,
				TaskFile:  r.TaskFile,
				AgentType: r.AgentType,
				CreatedAt: createdAt,
			})
		}
		data, err := json.Marshal(out)
		if err != nil {
			return fmt.Sprintf("error: %v\n", err)
		}
		return string(data) + "\n"

	default: // "text"
		var sb strings.Builder
		w := tabwriter.NewWriter(&sb, 0, 0, 2, ' ', 0)
		fmt.Fprintln(w, "TITLE\tSTATUS\tBRANCH\tPROGRAM\tTASK")
		for _, r := range records {
			fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n",
				r.Title,
				statusString(r.Status),
				r.Branch,
				r.Program,
				r.TaskFile,
			)
		}
		w.Flush()
		return sb.String()
	}
